56	    const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
57	    return new TextDecoder().decode(bytes);
58	  }
59	
60	  const bufferCtor = (globalThis as {
61	    Buffer?: {
62	      from(input: string, encoding: string): { toString(encoding: string): string };
63	    };
64	  }).Buffer;
65	
66	  if (bufferCtor) {
